import{_ as t,o as r,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"G03: 核心員工流動率審計 - 績效管理專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/4967_十銓/20260429/G03_核心員工流動率審計_績效管理專家.md","filePath":"審計報告庫/經營審計/4967_十銓/20260429/G03_核心員工流動率審計_績效管理專家.md"}'),o={name:"審計報告庫/經營審計/4967_十銓/20260429/G03_核心員工流動率審計_績效管理專家.md"};function l(n,a,s,_,h,d){return r(),e("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="g03-核心員工流動率審計-績效管理專家-審計報告" tabindex="-1">G03: 核心員工流動率審計 - 績效管理專家 審計報告 <a class="header-anchor" href="#g03-核心員工流動率審計-績效管理專家-審計報告" aria-label="Permalink to &quot;G03: 核心員工流動率審計 - 績效管理專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>核心技術或研發團隊的流動率為何？公司如何留住優秀人才？是否有關鍵人才流向競爭對手的跡象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p><strong>截至 2026 年最新數據，十銓缺離職率監測，研發主管 2022 年異動後團隊穩定，股權獎酬工具陸續退出。</strong> 現金分紅（員工酬勞佔淨利 10%）固可短期綁才，惟股權誘因退場將使景氣反轉時留才脆弱。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>評級：B（持平）</strong></li><li><strong>重點數據</strong>：員工人數 ~450 人，研發佔比 &gt;15%。2022 年研發副總離職後高層穩定。CSR 承認未追蹤離職率。員工福利費 CAGR 24%（3.87→5.96 億），獲利 CAGR 117%（2.36→11.10 億）。</li><li><strong>診斷見解</strong>：人均產值 3,852→4,540 萬，HCROI 1.61→2.86，組織效率顯著優化，屬良性排毒。惟流動率數據完全空白為內控重大缺口，核心人才流失風險無法量化評估。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-核心研發人員流動率與技術穩定性" tabindex="-1">1. 核心研發人員流動率與技術穩定性 <a class="header-anchor" href="#_1-核心研發人員流動率與技術穩定性" aria-label="Permalink to &quot;1. 核心研發人員流動率與技術穩定性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：無離職率統計，研發高層三年穩定</li><li><strong>深度見解</strong>：主管離職景氣低谷已接班，量化空白風險難評。建議建立離職面談以補缺口</li></ul><h3 id="_2-留才措施有效性評估" tabindex="-1">2. 留才措施有效性評估 <a class="header-anchor" href="#_2-留才措施有效性評估" aria-label="Permalink to &quot;2. 留才措施有效性評估&quot;">​</a></h3><ul><li><strong>核心重點</strong>：現金分紅暴增，股權獎酬工具退場</li><li><strong>深度見解</strong>：無鎖股約束景氣反轉時，純現金留才脆弱。同業競爭時純現金留才恐失效</li></ul><h3 id="_3-關鍵人才流向競爭對手之風險" tabindex="-1">3. 關鍵人才流向競爭對手之風險 <a class="header-anchor" href="#_3-關鍵人才流向競爭對手之風險" aria-label="Permalink to &quot;3. 關鍵人才流向競爭對手之風險&quot;">​</a></h3><ul><li><strong>核心重點</strong>：無挖角訴訟，分紅自然形成留才</li><li><strong>深度見解</strong>：獲利躍升分紅膨脹形成金手銬，景氣反轉脆弱。須密切關注同業動向與人才流向</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一：流動率黑箱——系統性內控缺失</strong>。CSR 報告明確承認「尚未追蹤自願與非自願離職率」。在約 450 人規模的科技公司，無法量化工時負載與離職原因，等於人力資本風險管理失明。若核心研發團隊年離職率 &gt;20%（對照記憶體模組業常態約 15~25%），將直接侵蝕連續三年年推 20+ 款新品的研發節奏。建議：若無法在 2026 年 CSR 報告補揭露離職率，應視為公司治理瑕疵。</p></li><li><p><strong>空頭風險二：股權激勵退場削弱中長期綁定力</strong>。庫藏股全數註銷（2024/11）、限制員工權利新股同步清理（2026/4），公司完全回歸純現金分紅模式。當景氣下滑導致獲利劇減（如 2022 年僅 70 萬淨利），員工酬勞將歸零，無股權工具可緩衝。2023 年員工薪資中位數僅 65.3 萬，低於消費性電子業界中位，若無分紅加成，薪酬競爭力不足以抵禦競爭對手低調挖角。物理對策：應恢復庫藏股並設計分批歸屬（cliff+graded vesting）之 RSU 方案。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: 未調用（人均薪資與福利費用已從年報 PDF 直接擷取）</li><li><strong>年報/財務報告</strong>: OK — 2023_Q4、2024_Q4、2025_Q4 合併財報，員工福利費用數據（P.44~P.46）、庫藏股註銷（2024 Q4 P.41）、員工酬勞估列（2025 Q4 P.46）</li><li><strong>CSR 永續報告書</strong>: 確認尚未追蹤員工離職率（Team Group 2024 CSR Report）</li><li><strong>Web Search</strong>: OK — 研發主管異動（鉅亨網 2022/11/25）、營收與淨利（公開資訊觀測站、自由財經）、員工薪資（Goodinfo / goodjob.life）、研發佔比 &gt;15%（富果法說摘要 2025/11）</li><li><strong>關鍵核對碼</strong>：員工福利費用 2025: $595,987K / 2024: $475,640K / 2023: $387,463K；員工薪資平均 2023: 79.9 萬；HCROI 2025: 2.86</li></ul>',19)])])}const u=t(o,[["render",l]]);export{g as __pageData,u as default};
